def parse_saml_response(saml_response):
    try:
        # Decode base64 encoded SAML response
        decoded_response = base64.b64decode(saml_response)
        
        # Parse XML
        root = ET.fromstring(decoded_response)
        
        # Validate presence of Assertion
        assertions = root.findall('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if not assertions:
            raise ValueError("No Assertion found in SAML response")
        
        # Extract user attributes from first assertion
        assertion = assertions[0]
        user_attributes = extract_user_attributes(assertion)
        
        # Create user session
        create_user_session(user_attributes)
        
        return True, user_attributes
        
    except Exception as e:
        return False, str(e)

def extract_user_attributes(assertion):
    attributes = {}
    
    # Extract subject (user identifier)
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    if subject is not None:
        name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
        if name_id is not None:
            attributes['user_id'] = name_id.text
    
    # Extract attributes
    attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
    for attr_stmt in attribute_statements:
        attributes_elements = attr_stmt.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES)
        for attr in attributes_elements:
            attr_name = attr.get('Name')
            attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
            if attr_values:
                attributes[attr_name] = [val.text for val in attr_values]
    
    return attributes

def create_user_session(user_attributes):
    session['user_id'] = user_attributes.get('user_id')
    session['attributes'] = user_attributes
    session['logged_in'] = True
    session['login_time'] = datetime.now().isoformat()

def validate_saml_assertion(assertion):
    # Check if assertion has required elements
    issuer = assertion.find('.//saml:Issuer', namespaces=SAML_NAMESPACES)
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NAMESPACES)
    auth_statement = assertion.find('.//saml:AuthnStatement', namespaces=SAML_NAMESPACES)
    
    if not all([issuer, subject, conditions, auth_statement]):
        return False
    
    # Validate time conditions
    not_before = conditions.get('NotBefore')
    not_on_or_after = conditions.get('NotOnOrAfter')
    
    if not_before:
        not_before_time = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
        if datetime.now() < not_before_time:
            return False
    
    if not_on_or_after:
        not_on_or_after_time = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
        if datetime.now() > not_on_or_after_time:
            return False
    
    return True

